#ifndef class_T
#define class_T float
#endif

#ifndef blockdim
#define blockdim 256
#endif

#ifndef ELEMENTS_PER_THREAD
#define ELEMENTS_PER_THREAD 8
#endif

#ifndef FUSION_DEGREE
#define FUSION_DEGREE 4
#endif

#ifndef COMPUTE_ITERATIONS
#define COMPUTE_ITERATIONS 0
#endif

// Type-specific helper functions
#ifdef ENABLE_HP
// For half2 type
static inline class_T conv_int(int i) {
    half h = (half)i;
    return (class_T){h, h};
}

static inline class_T mad_op(class_T a, class_T b, class_T c) {
    return mad(a, b, c);
}

static inline bool equal_op(class_T a, class_T b) {
    return (a.x == b.x) && (a.y == b.y);
}
#else
// For other types (int, float, double, short)
static inline class_T conv_int(int i) {
    return (class_T)i;
}

static inline class_T mad_op(class_T a, class_T b, class_T c) {
    return a * b + c;
}

static inline bool equal_op(class_T a, class_T b) {
    return a == b;
}
#endif

kernel void benchmark_func(class_T seed, class_T *g_data){
    const unsigned int blockSize = blockdim;
    const int stride = blockSize;
    int idx = get_group_id(0) * blockSize * ELEMENTS_PER_THREAD + get_local_id(0);
    const int big_stride = get_num_groups(0) * blockSize * ELEMENTS_PER_THREAD;

    class_T tmps[ELEMENTS_PER_THREAD];
    for(int k=0; k<FUSION_DEGREE; k++){
        for(int j=0; j<ELEMENTS_PER_THREAD; j++){
            tmps[j] = g_data[idx + j*stride + k*big_stride];

            #pragma unroll 4
            for(int i=0; i<COMPUTE_ITERATIONS; i++){
                tmps[j] = mad_op(tmps[j], tmps[j], seed);
            }
        }

        class_T sum = conv_int(0);
        #pragma unroll
        for(int j=0; j<ELEMENTS_PER_THREAD; j+=2)
            sum = mad_op(tmps[j], tmps[j+1], sum);

        if(equal_op(sum, conv_int(-1)))
            g_data[idx + k*big_stride] = sum;
    }
}
